def redis_cache(timeout):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = f'{func.__name__}-{args}-{kwargs}'
            result = redis_client.get(key)
            if result:
                return result.decode('utf-8')
            else:
                result = func(*args, **kwargs)
                redis_client.setex(key, timeout, result)
                return result
        return wrapper
    return decorator

